      check: (data: Output) => data is Refined,
      message?: string | { message: string; path?: (string | number)[] },
    ): ZodRefined<this, Refined>;
    refine(
      check: (data: Output) => boolean,
      message?: string | { message: string; path?: (string | number)[] },
    ): ZodRefined<this, Output>;
  }

  export interface ZodTypeDef {
    typeName: string;
  }

  export class ZodError extends Error {
    issues: ZodIssue[];
    errors: ZodIssue[];
    constructor(issues: ZodIssue[]);
  }

  export interface ZodIssue {
    code: string;
    path: (string | number)[];
    message: string;
  }

  export interface ZodString extends ZodType<string> {
    min(length: number): ZodString;
    max(length: number): ZodString;
    email(): ZodString;
    url(): ZodString;
    regex(regex: RegExp): ZodString;
    trim(): ZodString;
    toLowerCase(): ZodString;
    toUpperCase(): ZodString;
  }

  export interface ZodNumber extends ZodType<number> {
    min(value: number): ZodNumber;
    max(value: number): ZodNumber;
    positive(): ZodNumber;
    negative(): ZodNumber;
    int(): ZodNumber;
    nonnegative(): ZodNumber;
    nonpositive(): ZodNumber;
    multipleOf(value: number): ZodNumber;
    finite(): ZodNumber;
  }

  export interface ZodBoolean extends ZodType<boolean> {}

  export interface ZodNull extends ZodType<null> {}

  export interface ZodUndefined extends ZodType<undefined> {}

  export interface ZodArray<T extends ZodType> extends ZodType<T["_output"][]> {
    min(length: number): ZodArray<T>;
    max(length: number): ZodArray<T>;
    length(length: number): ZodArray<T>;
    nonempty(): ZodArray<T>;
  }

  export interface ZodObject<
    T extends Record<string, ZodType>,
  > extends ZodType<{
    [K in keyof T]: T[K]["_output"];
  }> {
    shape: T;
    extend<U extends Record<string, ZodType>>(shape: U): ZodObject<T & U>;
    merge<U extends ZodObject<any>>(other: U): ZodObject<T & U["shape"]>;
    pick<K extends keyof T>(keys: { [P in K]: true }): ZodObject<Pick<T, K>>;
    omit<K extends keyof T>(keys: { [P in K]: true }): ZodObject<Omit<T, K>>;
    partial(): ZodObject<{
      [K in keyof T]: ZodOptional<T[K]>;
    }>;
    required(): ZodObject<{
      [K in keyof T]: T[K] extends ZodOptional<infer U> ? U : T[K];
    }>;
    strict(): ZodObject<T>;
    passthrough(): ZodObject<T>;
  }

  export interface ZodUnion<
    T extends readonly [ZodType, ...ZodType[]],
  > extends ZodType<T[number]["_output"]> {}

  export interface ZodLiteral<
    T extends string | number | boolean | null | undefined,
  > extends ZodType<T> {}

  export interface ZodEnum<
    T extends readonly [string, ...string[]],
  > extends ZodType<T[number]> {}

  export interface ZodOptional<T extends ZodType> extends ZodType<
    T["_output"] | undefined
  > {}

  export interface ZodNullable<T extends ZodType> extends ZodType<
    T["_output"] | null
  > {}

  export interface ZodNullish<T extends ZodType> extends ZodType<
    T["_output"] | null | undefined
  > {}

  export interface ZodDefault<T extends ZodType> extends ZodType<
    T["_output"]
  > {}

  export interface ZodTransform<
    T extends ZodType,
    Output,
  > extends ZodType<Output> {}

  export interface ZodRefined<
    T extends ZodType,
    Output = T["_output"],
  > extends ZodType<Output> {}

  export interface ZodRecord<
    K extends ZodType = ZodString,
    V extends ZodType = ZodType,
  > extends ZodType<Record<K["_output"], V["_output"]>> {}

  export interface ZodDiscriminatedUnion<
    K extends string,
    T extends readonly ZodObject<any>[],
  > extends ZodType<T[number]["_output"]> {}

  export interface ZodSchema<T = any> extends ZodType<T> {
    _output: T;
  }

  export const z: {
    string(): ZodString;
    number(): ZodNumber;
    boolean(): ZodBoolean;
    null(): ZodNull;
    undefined(): ZodUndefined;
    array<T extends ZodType>(schema: T): ZodArray<T>;
    object<T extends Record<string, ZodType>>(shape: T): ZodObject<T>;
    union<T extends readonly [ZodType, ...ZodType[]]>(schemas: T): ZodUnion<T>;
    literal<T extends string | number | boolean | null | undefined>(
      value: T,
    ): ZodLiteral<T>;
    enum<T extends readonly [string, ...string[]]>(values: T): ZodEnum<T>;
    record<K extends ZodType = ZodString, V extends ZodType = ZodType>(
      keySchema?: K,
      valueSchema?: V,
    ): ZodRecord<K, V>;
    discriminatedUnion<K extends string, T extends readonly ZodObject<any>[]>(
      discriminator: K,
      schemas: T,
    ): ZodDiscriminatedUnion<K, T>;

    ZodError: typeof ZodError;
  };

  export namespace z {
    export type infer<T extends ZodType<any, any, any>> = T["_output"];
  }

  export default z;
}

